const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

const isAlive = (count: number, wasAlive: boolean): boolean =>
  count === 3 || (count === 2 && wasAlive);

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(cellKey));
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const entry = counts.get(key) ?? { cell: neighbor, count: 0 };
      entry.count += 1;
      counts.set(key, entry);
    }
  }
  return [...counts].flatMap(([key, { cell, count }]) =>
    isAlive(count, liveKeys.has(key)) ? [cell] : []
  );
}
